import React, { useState } from 'react';
import { Link } from 'react-router-dom';
import { Button, Container, Typography, Box, Paper, TextField, MenuItem, CircularProgress } from '@mui/material';
import CodeIcon from '@mui/icons-material/Code';
import RecordVoiceOverIcon from '@mui/icons-material/RecordVoiceOver';
import apiService from '../services/apiService';
import { useVoiceControl } from '../context/VoiceControlContext';

const HomePage = () => {
    const { speakFeedback } = useVoiceControl();
    const [craftingPrompt, setCraftingPrompt] = useState('');
    const [craftingLang, setCraftingLang] = useState('python');
    const [craftingLoading, setCraftingLoading] = useState(false);
    const [craftedCode, setCraftedCode] = useState('');

    const handleCraft = async () => {
        if (!craftingPrompt.trim()) return;
        setCraftingLoading(true);
        setCraftedCode('');
        try {
            const res = await apiService.generateCode(craftingPrompt, craftingLang, false);
            const code = res?.generated_code || res?.code || JSON.stringify(res);
            setCraftedCode(code);
            speakFeedback('Code crafted successfully');
        } catch (e) {
            console.error(e);
            speakFeedback('Failed to craft code');
        } finally {
            setCraftingLoading(false);
        }
    };

    return (
        <Container maxWidth="md">
            <Box sx={{ mt: 8, textAlign: 'center' }}>
                <Typography variant="h2" component="h1" gutterBottom>
                    Voice Controlled IDE
                </Typography>
                <Typography variant="h5" color="textSecondary" paragraph>
                    An accessible development environment for programmers with motor disabilities
                </Typography>
                
                <Box sx={{ mt: 4, display: 'flex', justifyContent: 'center', gap: 4, flexWrap: 'wrap' }}>
                    <Paper 
                        elevation={3}
                        sx={{ p: 3, display: 'flex', flexDirection: 'column', alignItems: 'center', width: 250 }}
                    >
                        <CodeIcon sx={{ fontSize: 60, mb: 2 }} />
                        <Typography variant="h6" gutterBottom>
                            Code Generation
                        </Typography>
                        <Typography variant="body2" color="textSecondary" paragraph>
                            Generate code using voice commands and AI assistance
                        </Typography>
                        <Button 
                            component={Link}
                            to="/code-generation"
                            variant="contained" 
                            color="primary"
                            sx={{ mt: 2 }}
                        >
                            Get Started
                        </Button>
                    </Paper>

                    <Paper 
                        elevation={3}
                        sx={{ p: 3, display: 'flex', flexDirection: 'column', alignItems: 'center', width: 250 }}
                    >
                        <RecordVoiceOverIcon sx={{ fontSize: 60, mb: 2 }} />
                        <Typography variant="h6" gutterBottom>
                            Code Transcription
                        </Typography>
                        <Typography variant="body2" color="textSecondary" paragraph>
                            Convert your voice directly into code in real-time
                        </Typography>
                        <Button 
                            component={Link}
                            to="/code-transcription"
                            variant="contained" 
                            color="primary"
                            sx={{ mt: 2 }}
                        >
                            Start Transcribing
                        </Button>
                    </Paper>

                    <Paper 
                        elevation={3}
                        sx={{ p: 3, display: 'flex', flexDirection: 'column', width: 520 }}
                    >
                        <Typography variant="h6" gutterBottom>
                            Code Crafting
                        </Typography>
                        <Typography variant="body2" color="textSecondary" paragraph>
                            Describe the code and the logic, and we’ll generate it using Groq.
                        </Typography>
                        <TextField
                            multiline
                            rows={3}
                            placeholder="e.g., Write a Python function that merges two sorted arrays."
                            value={craftingPrompt}
                            onChange={(e) => setCraftingPrompt(e.target.value)}
                            sx={{ mb: 2 }}
                        />
                        <Box sx={{ display: 'flex', gap: 2, alignItems: 'center', mb: 2 }}>
                            <TextField select label="Language" size="small" value={craftingLang} onChange={(e) => setCraftingLang(e.target.value)}>
                                {['python','javascript','typescript','java','c++','go','rust'].map(l => (
                                    <MenuItem key={l} value={l}>{l}</MenuItem>
                                ))}
                            </TextField>
                            <Button variant="contained" onClick={handleCraft} disabled={craftingLoading || !craftingPrompt.trim()}>
                                {craftingLoading ? <CircularProgress size={20} /> : 'Craft Code'}
                            </Button>
                        </Box>
                        {craftedCode && (
                            <Box sx={{ bgcolor: 'grey.900', borderRadius: 1, p: 2, maxHeight: 240, overflow: 'auto', fontFamily: 'monospace', whiteSpace: 'pre' }}>
                                {craftedCode}
                            </Box>
                        )}
                    </Paper>
                </Box>
            </Box>
        </Container>
    );
};

export default HomePage;
